DROP TABLE IF EXISTS `profiles`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `profiles` (
  `id` int NOT NULL AUTO_INCREMENT,
  `userId` int NOT NULL,
  `linkedInUrl` varchar(255) NOT NULL,
  `professionalCourses` json DEFAULT NULL,
  `licenses` json DEFAULT NULL,
  `certifications` json DEFAULT NULL,
  `profileImage` varchar(255) DEFAULT NULL,
  `alumniOfTheDayWins` json DEFAULT NULL,
  `eventsAttended` int DEFAULT '0',
  `createdAt` datetime NOT NULL,
  `updatedAt` datetime NOT NULL,
  `programme` varchar(255) DEFAULT NULL,
  `graduationYear` int DEFAULT NULL,
  `industrySector` varchar(255) DEFAULT NULL,
  `currentRole` varchar(255) DEFAULT NULL,
